/* Minimal MQTT-over-WebSocket client — ES5, zero dipendenze
 * API compatibile con il subset di mqtt.js usato in index.html:
 *   mqtt.connect(url, opts)  →  client
 *   client.on(event, cb)     events: connect, reconnect, close, error, message(topic, payload)
 *   client.subscribe(topic, opts, cb)
 *   client.publish(topic, payload, opts, cb)
 *   client.end(force)
 *   client.connected         (boolean)
 */
;(function (root) {
  'use strict';

  /* ── UTF-8 encode ──────────────────────────────────────────── */
  function utf8Encode(str) {
    var out = [];
    for (var i = 0; i < str.length; i++) {
      var c = str.charCodeAt(i);
      if (c < 0x80) {
        out.push(c);
      } else if (c < 0x800) {
        out.push(0xC0 | (c >> 6), 0x80 | (c & 0x3F));
      } else {
        out.push(0xE0 | (c >> 12), 0x80 | ((c >> 6) & 0x3F), 0x80 | (c & 0x3F));
      }
    }
    return out;
  }

  /* ── UTF-8 decode ──────────────────────────────────────────── */
  function utf8Decode(arr) {
    var s = '';
    var i = 0;
    while (i < arr.length) {
      var b = arr[i];
      if (b < 0x80) { s += String.fromCharCode(b); i++; }
      else if (b < 0xE0) { s += String.fromCharCode(((b & 0x1F) << 6) | (arr[i+1] & 0x3F)); i += 2; }
      else { s += String.fromCharCode(((b & 0x0F) << 12) | ((arr[i+1] & 0x3F) << 6) | (arr[i+2] & 0x3F)); i += 3; }
    }
    return s;
  }

  /* ── MQTT encoding helpers ─────────────────────────────────── */
  function encStr(str) {
    var b = utf8Encode(str);
    return [b.length >> 8, b.length & 0xFF].concat(b);
  }

  function encRemLen(n) {
    var out = [];
    do { var d = n % 128; n = n >> 7; if (n > 0) d |= 0x80; out.push(d); } while (n > 0);
    return out;
  }

  function buildPkt(type, flags, header, payload) {
    var body = (header || []).concat(payload || []);
    var fixed = [(type << 4) | (flags || 0)].concat(encRemLen(body.length));
    return new Uint8Array(fixed.concat(body));
  }

  /* ── Packet builders ───────────────────────────────────────── */
  function mkConnect(clientId, keepAlive) {
    return buildPkt(1, 0,
      [0x00,0x04, 0x4D,0x51,0x54,0x54, 0x04, 0x02,
       keepAlive >> 8, keepAlive & 0xFF],
      encStr(clientId));
  }

  function mkSubscribe(id, topic, qos) {
    return buildPkt(8, 2, [id >> 8, id & 0xFF], encStr(topic).concat([qos]));
  }

  function mkPublish(topic, payload, qos, id) {
    var h = encStr(topic);
    if (qos > 0) h = h.concat([id >> 8, id & 0xFF]);
    return buildPkt(3, qos << 1, h, utf8Encode(payload));
  }

  function mkPuback(id)   { return buildPkt(4, 0, [id >> 8, id & 0xFF], []); }
  function mkPingreq()    { return new Uint8Array([0xC0, 0x00]); }
  function mkDisconnect() { return new Uint8Array([0xE0, 0x00]); }

  /* ── Packet decoder ────────────────────────────────────────── */
  function decRemLen(buf, off) {
    var mult = 1, val = 0, pos = off, d;
    do { d = buf[pos++]; val += (d & 0x7F) * mult; mult *= 128; } while (d & 0x80);
    return { val: val, end: pos };
  }

  function decStr(buf, off) {
    var len = (buf[off] << 8) | buf[off+1];
    return { val: utf8Decode(buf.subarray(off+2, off+2+len)), next: off+2+len };
  }

  function decodePacket(data) {
    var buf = new Uint8Array(data);
    if (buf.length < 2) return null;
    var type  = (buf[0] >> 4) & 0x0F;
    var flags = buf[0] & 0x0F;
    var rl    = decRemLen(buf, 1);
    var off   = rl.end;
    var end   = rl.end + rl.val;

    if (type === 2) {
      return { type: 'CONNACK', rc: buf[off+1] };
    }
    if (type === 3) {
      var qos = (flags >> 1) & 0x03;
      var ts  = decStr(buf, off);
      var poff = ts.next;
      var pid  = 0;
      if (qos > 0) { pid = (buf[poff] << 8) | buf[poff+1]; poff += 2; }
      return { type: 'PUBLISH', qos: qos, topic: ts.val, pid: pid, raw: buf.subarray(poff, end) };
    }
    if (type === 4) { return { type: 'PUBACK',  pid: (buf[off] << 8) | buf[off+1] }; }
    if (type === 9) { return { type: 'SUBACK',  pid: (buf[off] << 8) | buf[off+1] }; }
    if (type === 13){ return { type: 'PINGRESP' }; }
    return { type: 'UNKNOWN' };
  }

  /* ── MqttClient ────────────────────────────────────────────── */
  function MqttClient(url, opts) {
    this.url        = url;
    this.connected  = false;
    this._opts      = opts || {};
    this._handlers  = {};
    this._pid       = 1;
    this._cbs       = {};
    this._ws        = null;
    this._rTimer    = null;
    this._pingTimer = null;
    this._stopped   = false;
    this._rPeriod   = this._opts.reconnectPeriod !== undefined ? this._opts.reconnectPeriod : 3000;
    this._keepAlive = 60;
    this._clientId  = this._opts.clientId || ('mqttc_' + Math.random().toString(16).slice(2, 8));
    this._doConnect();
  }

  MqttClient.prototype.on = function (ev, fn) {
    if (!this._handlers[ev]) this._handlers[ev] = [];
    this._handlers[ev].push(fn);
    return this;
  };

  MqttClient.prototype._emit = function (ev) {
    var args = Array.prototype.slice.call(arguments, 1);
    var hs = this._handlers[ev] || [];
    for (var i = 0; i < hs.length; i++) { try { hs[i].apply(null, args); } catch(e) {} }
  };

  MqttClient.prototype._nextPid = function () {
    var id = this._pid++;
    if (this._pid > 65535) this._pid = 1;
    return id;
  };

  MqttClient.prototype._doConnect = function () {
    if (this._stopped) return;
    var self = this;
    if (self._ws) { try { self._ws.close(); } catch(e) {} self._ws = null; }
    var ws;
    try { ws = new WebSocket(self.url, ['mqtt']); }
    catch(e) { self._emit('error', e); self._schedReconnect(); return; }
    ws.binaryType = 'arraybuffer';
    self._ws = ws;

    ws.onopen = function () { ws.send(mkConnect(self._clientId, self._keepAlive)); };
    ws.onmessage = function (e) { self._onData(e.data); };
    ws.onerror = function (e) {
      self._emit('error', e instanceof Error ? e : new Error('WebSocket error'));
    };
    ws.onclose = function () {
      self._stopPing();
      if (self.connected) { self.connected = false; self._emit('close'); }
      self._schedReconnect();
    };
  };

  MqttClient.prototype._onData = function (data) {
    var self = this;
    var p = decodePacket(data);
    if (!p) return;

    if (p.type === 'CONNACK') {
      if (p.rc === 0) {
        self.connected = true;
        self._startPing();
        self._emit('connect');
      } else {
        self._emit('error', new Error('CONNACK rc=' + p.rc));
      }
    } else if (p.type === 'PUBLISH') {
      if (p.qos === 1) { try { self._ws.send(mkPuback(p.pid)); } catch(e) {} }
      var rawRef = p.raw;
      var payload = {
        _r: rawRef,
        toString: function() { return utf8Decode(this._r); }
      };
      self._emit('message', p.topic, payload);
    } else if (p.type === 'PUBACK' || p.type === 'SUBACK') {
      var cb = self._cbs[p.pid];
      if (cb) { delete self._cbs[p.pid]; cb(null); }
    }
  };

  MqttClient.prototype._schedReconnect = function () {
    var self = this;
    if (self._stopped || self._rPeriod <= 0 || self._rTimer) return;
    self._rTimer = setTimeout(function () {
      self._rTimer = null;
      if (!self.connected && !self._stopped) { self._emit('reconnect'); self._doConnect(); }
    }, self._rPeriod);
  };

  MqttClient.prototype._startPing = function () {
    var self = this;
    self._stopPing();
    self._pingTimer = setInterval(function () {
      if (self._ws && self._ws.readyState === 1) { try { self._ws.send(mkPingreq()); } catch(e) {} }
    }, (self._keepAlive * 1000) / 2);
  };

  MqttClient.prototype._stopPing = function () {
    if (this._pingTimer) { clearInterval(this._pingTimer); this._pingTimer = null; }
  };

  MqttClient.prototype.subscribe = function (topic, opts, cb) {
    if (!this.connected) { if (cb) cb(new Error('not connected')); return this; }
    var qos = (opts && opts.qos) || 0;
    var id  = this._nextPid();
    if (cb) this._cbs[id] = cb;
    try { this._ws.send(mkSubscribe(id, topic, qos)); } catch(e) { if (cb) cb(e); }
    return this;
  };

  MqttClient.prototype.publish = function (topic, payload, opts, cb) {
    if (!this.connected) { if (cb) cb(new Error('not connected')); return this; }
    var qos = (opts && opts.qos) || 0;
    var id  = qos > 0 ? this._nextPid() : 0;
    var str = (typeof payload === 'string') ? payload : String(payload);
    if (qos > 0 && cb) this._cbs[id] = cb;
    try {
      this._ws.send(mkPublish(topic, str, qos, id));
      if (qos === 0 && cb) setTimeout(function() { cb(null); }, 0);
    } catch(e) { if (cb) cb(e); }
    return this;
  };

  MqttClient.prototype.end = function (force) {
    this._stopped = true;
    this._stopPing();
    if (this._rTimer) { clearTimeout(this._rTimer); this._rTimer = null; }
    if (this._ws) {
      if (!force && this.connected) { try { this._ws.send(mkDisconnect()); } catch(e) {} }
      try { this._ws.close(); } catch(e) {}
      this._ws = null;
    }
    this.connected = false;
    return this;
  };

  /* ── Export ────────────────────────────────────────────────── */
  root.mqtt = { connect: function(url, opts) { return new MqttClient(url, opts); } };

}(typeof window !== 'undefined' ? window : this));
